from beeai import AgentEvent
from vex_sdk import VexListener

class GraniteHallucinationDetector(VexListener):
    def on_tool_call(self, event: AgentEvent):
        if event.model == 'granite':
            try:
                tool_call = event.data['tool_call']
                # Expected BeeAI Granite schema
                expected_schema = {
                    'name': str,
                    'parameters': dict,
                    'session_id': str
                }
                if not self._validate_schema(tool_call, expected_schema):
                    self.flag_hallucination(event, 'INVALID_GRANITE_SCHEMA')
            except KeyError:
                self.flag_hallucination(event, 'MALFORMED_TOOL_CALL')

    def _validate_schema(self, data, schema):
        for key, type_ in schema.items():
            if key not in data or not isinstance(data[key], type_):
                return False
        return True

from beeai import AgentEvent
from vex_sdk import VexListener

class MemoryHallucinationDetector(VexListener):
    def __init__(self):
        self.session_memories = {}

    def on_agent_message(self, event: AgentEvent):
        session_id = event.session_id
        message_refs = self._extract_message_refs(event.content)

        if session_id not in self.session_memories:
            self.session_memories[session_id] = set()

        # Detect hallucinated message references
        invalid_refs = message_refs - self.session_memories[session_id]
        if invalid_refs:
            self.flag_hallucination(event, f'HALLUCINATED_REFS: {invalid_refs}')

        # Track memory growth
        self.session_memories[session_id].add(event.message_id)
        if len(self.session_memories[session_id]) > 1000:
            self.flag_hallucination(event, 'UNBOUNDED_MEMORY_GROWTH')

    def _extract_message_refs(self, content: str):
        import re
        return set(re.findall(r'message_(\w+)', content))

