        params = event.data.get('tool_call', {}).get('parameters', {})

        if tool_name in self.TOOL_RULES:
            validator = self.TOOL_RULES[tool_name]
            for param, rule in validator.items():
                if param not in params or not rule(params[param]):
                    self.flag_hallucination(
                        event, 
                        f'TOOL_PARAM_HALLUCINATION: {tool_name}.{param}'
                    )

