from beeai import AgentEvent
from vex_sdk import VexListener
import json

class GraniteNormalizer(VexListener):
    def on_tool_call(self, event: AgentEvent):
        if event.model.startswith('granite'):
            try:
                raw_output = event.data['raw_output']
                normalized = self._normalize_granite_output(raw_output)
                event.data['tool_call'] = normalized
                self.log_fix(event, 'NORMALIZED_GRANITE_OUTPUT')
            except Exception as e:
                self.flag_hallucination(event, f'NORMALIZATION_FAILED: {e}')

    def _normalize_granite_output(self, raw_output: str):
        # BeeAI Granite common format issues
        if raw_output.startswith('```json'):
            raw_output = raw_output.replace('```json', '').replace('```', '')

        parsed = json.loads(raw_output)
        return {
            'name': parsed.get('function', parsed.get('name', '')),
            'parameters': parsed.get('arguments', parsed.get('parameters', {})),
            'session_id': parsed.get('session_id', 'unknown')
        }

from beeai import AgentEvent
from vex_sdk import VexListener

class MemoryPruner(VexListener):
    MAX_MEMORY_SIZE = 500

    def __init__(self):
        self.session_histories = {}

    def on_agent_message(self, event: AgentEvent):
        session_id = event.session_id
        if session_id not in self.session_histories:
            self.session_histories[session_id] = []

        self.session_histories[session_id].append(event.message_id)

        if len(self.session_histories[session_id]) > self.MAX_MEMORY_SIZE:
            # Prune oldest 50% of memory
            cutoff = len(self.session_histories[session_id]) // 2
            pruned = self.session_histories[session_id][cutoff:]
            self.session_histories[session_id] = pruned

            # Notify BeeAI memory manager
            event.agent.memory.prune_messages(
                [msg_id for msg_id in self.session_histories[session_id][:cutoff]]
            )
            self.log_fix(event, f'MEMORY_PRUNED: {cutoff} messages')

from beeai import AgentEvent
from vex_sdk import VexListener
from difflib import get_close_matches

class ToolParameterFixer(VexListener):
    VALID_OPERATIONS = ['add', 'subtract', 'multiply', 'divide']
    VALID_EMAIL_DOMAINS = ['gmail.com', 'yahoo.com', 'outlook.com']

    def on_tool_call(self, event: AgentEvent):
        tool_call = event.data['tool_call']
        params = tool_call['parameters']
        fixed = False

        if tool_call['name'] == 'calculator':
            op = params.get('operation')
            if op not in self.VALID_OPERATIONS:
                closest = get_close_matches(op, self.VALID_OPERATIONS, n=1, cutoff=0.6)
                if closest:
                    params['operation'] = closest[0]
                    fixed = True

        if tool_call['name'] == 'email' and 'to' in params:
            email = params['to']
            if '@' not in email:
                closest_domain = get_close_matches(email, self.VALID_EMAIL_DOMAINS, n=1)
                if closest_domain:
                    params['to'] = f'user@{closest_domain[0]}'
                    fixed = True

        if fixed:
            event.data['tool_call']['parameters'] = params
            self.log_fix(event, 'TOOL_PARAMS_CORRECTED')
